import sys

def count_pairs_with_sum_at_most_t(numbers, t):
    numbers.sort()
    left, right = 0, len(numbers) - 1
    count = 0
    while left < right:
        if numbers[left] + numbers[right] <= t:
            count += right - left
            left += 1
        else:
            right -= 1
    return count

def main():
    n, t = map(int, input().split())
    numbers = list(map(int, input().split()))
    print(count_pairs_with_sum_at_most_t(numbers, t))

if __name__ == "__main__":
