    p = []
    for i, x in enumerate(a):
        j = bisect.bisect_right(s, x)
        if j == len(s):
            s.append(x)
            p.append(i)
        else:
            s[j] = x
            p[j] = i
    m = 0
    for i, x in enumerate(a):
        j = bisect.bisect_right(s, x)
        if j > 0:
            m = max(m, p[j-1] - i)
        if j < len(s):
            m = max(m, p[j] - i)
        k = bisect.bisect_left(s, x)
        if k < len(s):
            m = max(m, p[k] - i)
    print(m)

